WITH toDate('2024-07-01') AS peak_month, base AS ( SELECT OriginCode, OriginCityName, DestCode, DestCityName, DepDelay, DepDel15 FROM ontime.fact_ontime WHERE Carrier = 'AA' AND Cancelled = 0 AND DepDelay IS NOT NULL AND toStartOfMonth(FlightDate) = peak_month ), network AS ( SELECT count() AS network_flights, sum(greatest(DepDelay, 0)) AS network_delay_minutes FROM base ), routes AS ( SELECT concat(OriginCode, '-', DestCode) AS route, any(OriginCityName) AS origin_city, any(DestCityName) AS dest_city, count() AS flights, round(avg(DepDelay), 2) AS avg_dep_delay, round(avg(DepDel15) * 100, 2) AS pct_dep_15_plus, sum(greatest(DepDelay, 0)) AS total_dep_delay_minutes FROM base GROUP BY OriginCode, DestCode ) SELECT route, origin_city, dest_city, flights, avg_dep_delay, pct_dep_15_plus, total_dep_delay_minutes, round(total_dep_delay_minutes / network_delay_minutes * 100, 2) AS network_delay_share_pct, round(flights / network_flights * 100, 2) AS network_flight_share_pct FROM routes CROSS JOIN network WHERE flights >= 150 ORDER BY total_dep_delay_minutes DESC, flights DESC
